## Overview and Purpose

This bead connects the symbolic obligation system (from the RaptorQ-based distributed layer) with the existing runtime obligation tracking infrastructure. The goal is to unify obligation semantics across both local async operations and distributed symbol-based operations, ensuring that:

1. **Symbolic obligations** (symbol transmission, acknowledgments, lease-based resources) integrate with the existing `ObligationRecord` system
2. **Lifetime tracking** for symbols respects region boundaries and epoch windows
3. **Drop semantics** ensure proper cleanup when symbol-based obligations are not resolved

The existing obligation system (`src/record/obligation.rs`) provides a robust two-phase protocol (Reserved -> Committed/Aborted/Leaked). This bead extends that foundation to handle the unique requirements of distributed symbol operations.

## Core Types

```rust
//! Symbol obligation types for distributed operations.
//!
//! Extends the core obligation system to support RaptorQ symbol semantics.

use crate::record::obligation::{ObligationKind, ObligationRecord, ObligationState};
use crate::types::symbol::{ObjectId, SymbolId};
use crate::types::{ObligationId, RegionId, TaskId, Time};

/// Extended obligation kinds for symbol operations.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum SymbolObligationKind {
    /// Obligation to transmit a symbol to a destination.
    /// Committed when acknowledged, aborted on timeout/failure.
    SymbolTransmit {
        symbol_id: SymbolId,
        destination: RegionId,
    },

    /// Obligation to acknowledge receipt of a symbol.
    /// Must be committed before region close.
    SymbolAck {
        symbol_id: SymbolId,
        source: RegionId,
    },

    /// Obligation representing a decoding operation in progress.
    /// Committed when object is fully decoded.
    DecodingInProgress {
        object_id: ObjectId,
        symbols_received: u32,
        symbols_needed: u32,
    },

    /// Obligation for holding an encoding session open.
    /// Must be resolved before session resources are released.
    EncodingSession {
        object_id: ObjectId,
        symbols_encoded: u32,
    },

    /// Lease obligation for remote resource access.
    /// Must be renewed or released before expiry.
    SymbolLease {
        object_id: ObjectId,
        lease_expires: Time,
    },
}

/// A symbolic obligation that wraps the core obligation with symbol-specific metadata.
#[derive(Debug)]
pub struct SymbolicObligation {
    /// The underlying obligation record.
    inner: ObligationRecord,

    /// Symbol-specific obligation details.
    kind: SymbolObligationKind,

    /// The epoch window during which this obligation is valid.
    /// None means valid for any epoch (local-only obligation).
    valid_epoch: Option<EpochWindow>,

    /// Timestamp when the obligation was created.
    created_at: Time,

    /// Optional deadline for automatic abort if not resolved.
    deadline: Option<Time>,
}

/// Window of epochs during which an obligation is valid.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct EpochWindow {
    /// Starting epoch (inclusive).
    pub start: EpochId,
    /// Ending epoch (inclusive).
    pub end: EpochId,
}

/// Identifier for an epoch in the distributed system.
#[derive(Debug, Clone, Copy, PartialEq, Eq, PartialOrd, Ord, Hash)]
pub struct EpochId(pub u64);

impl SymbolicObligation {
    /// Creates a new symbol transmit obligation.
    pub fn transmit(
        id: ObligationId,
        holder: TaskId,
        region: RegionId,
        symbol_id: SymbolId,
        destination: RegionId,
        deadline: Option<Time>,
        epoch_window: Option<EpochWindow>,
    ) -> Self {
        Self {
            inner: ObligationRecord::new(id, ObligationKind::IoOp, holder, region),
            kind: SymbolObligationKind::SymbolTransmit {
                symbol_id,
                destination,
            },
            valid_epoch: epoch_window,
            created_at: Time::ZERO, // Set by runtime
            deadline,
        }
    }

    /// Creates a new symbol acknowledgment obligation.
    pub fn ack(
        id: ObligationId,
        holder: TaskId,
        region: RegionId,
        symbol_id: SymbolId,
        source: RegionId,
    ) -> Self {
        Self {
            inner: ObligationRecord::new(id, ObligationKind::Ack, holder, region),
            kind: SymbolObligationKind::SymbolAck { symbol_id, source },
            valid_epoch: None,
            created_at: Time::ZERO,
            deadline: None,
        }
    }

    /// Creates a decoding progress obligation.
    pub fn decoding(
        id: ObligationId,
        holder: TaskId,
        region: RegionId,
        object_id: ObjectId,
        symbols_needed: u32,
        epoch_window: EpochWindow,
    ) -> Self {
        Self {
            inner: ObligationRecord::new(id, ObligationKind::IoOp, holder, region),
            kind: SymbolObligationKind::DecodingInProgress {
                object_id,
                symbols_received: 0,
                symbols_needed,
            },
            valid_epoch: Some(epoch_window),
            created_at: Time::ZERO,
            deadline: None,
        }
    }

    /// Creates a lease obligation.
    pub fn lease(
        id: ObligationId,
        holder: TaskId,
        region: RegionId,
        object_id: ObjectId,
        lease_expires: Time,
    ) -> Self {
        Self {
            inner: ObligationRecord::new(id, ObligationKind::Lease, holder, region),
            kind: SymbolObligationKind::SymbolLease {
                object_id,
                lease_expires,
            },
            valid_epoch: None,
            created_at: Time::ZERO,
            deadline: Some(lease_expires),
        }
    }

    /// Returns true if this obligation is pending (not resolved).
    #[must_use]
    pub fn is_pending(&self) -> bool {
        self.inner.is_pending()
    }

    /// Returns true if this obligation is within its valid epoch window.
    #[must_use]
    pub fn is_epoch_valid(&self, current_epoch: EpochId) -> bool {
        match self.valid_epoch {
            None => true,
            Some(window) => current_epoch >= window.start && current_epoch <= window.end,
        }
    }

    /// Returns true if this obligation has passed its deadline.
    #[must_use]
    pub fn is_expired(&self, now: Time) -> bool {
        match self.deadline {
            None => false,
            Some(deadline) => now > deadline,
        }
    }

    /// Commits the obligation (successful resolution).
    ///
    /// # Panics
    /// Panics if already resolved.
    pub fn commit(&mut self) {
        self.inner.commit();
    }

    /// Aborts the obligation (clean cancellation).
    ///
    /// # Panics
    /// Panics if already resolved.
    pub fn abort(&mut self) {
        self.inner.abort();
    }

    /// Marks the obligation as leaked.
    ///
    /// Called by the runtime when it detects that an obligation holder
    /// completed without resolving the obligation.
    ///
    /// # Panics
    /// Panics if already resolved.
    pub fn mark_leaked(&mut self) {
        self.inner.mark_leaked();
    }

    /// Updates decoding progress.
    ///
    /// # Panics
    /// Panics if this is not a decoding obligation.
    pub fn update_decoding_progress(&mut self, symbols_received: u32) {
        if let SymbolObligationKind::DecodingInProgress {
            symbols_received: ref mut count,
            ..
        } = self.kind
        {
            *count = symbols_received;
        } else {
            panic!("not a decoding obligation");
        }
    }

    /// Returns the symbol-specific obligation kind.
    #[must_use]
    pub fn symbol_kind(&self) -> &SymbolObligationKind {
        &self.kind
    }

    /// Returns the underlying obligation state.
    #[must_use]
    pub fn state(&self) -> ObligationState {
        self.inner.state
    }

    /// Returns the obligation ID.
    #[must_use]
    pub fn id(&self) -> ObligationId {
        self.inner.id
    }
}

/// Tracker for managing symbolic obligations within a region.
#[derive(Debug)]
pub struct SymbolicObligationTracker {
    /// Pending obligations indexed by ID.
    obligations: std::collections::HashMap<ObligationId, SymbolicObligation>,

    /// Index by symbol ID for fast lookup.
    by_symbol: std::collections::HashMap<SymbolId, Vec<ObligationId>>,

    /// Index by object ID for decoding/encoding obligations.
    by_object: std::collections::HashMap<ObjectId, Vec<ObligationId>>,

    /// Counter for generating obligation IDs.
    next_id: u32,

    /// The region this tracker belongs to.
    region_id: RegionId,
}

impl SymbolicObligationTracker {
    /// Creates a new tracker for the given region.
    pub fn new(region_id: RegionId) -> Self {
        Self {
            obligations: std::collections::HashMap::new(),
            by_symbol: std::collections::HashMap::new(),
            by_object: std::collections::HashMap::new(),
            next_id: 0,
            region_id,
        }
    }

    /// Registers a new symbolic obligation.
    pub fn register(&mut self, mut obligation: SymbolicObligation) -> ObligationId {
        let id = obligation.id();

        // Index by symbol if applicable
        match &obligation.kind {
            SymbolObligationKind::SymbolTransmit { symbol_id, .. }
            | SymbolObligationKind::SymbolAck { symbol_id, .. } => {
                self.by_symbol
                    .entry(*symbol_id)
                    .or_default()
                    .push(id);
            }
            SymbolObligationKind::DecodingInProgress { object_id, .. }
            | SymbolObligationKind::EncodingSession { object_id, .. }
            | SymbolObligationKind::SymbolLease { object_id, .. } => {
                self.by_object
                    .entry(*object_id)
                    .or_default()
                    .push(id);
            }
        }

        self.obligations.insert(id, obligation);
        id
    }

    /// Resolves an obligation by ID.
    pub fn resolve(&mut self, id: ObligationId, commit: bool) -> Option<SymbolicObligation> {
        if let Some(mut ob) = self.obligations.remove(&id) {
            if commit {
                ob.commit();
            } else {
                ob.abort();
            }
            Some(ob)
        } else {
            None
        }
    }

    /// Returns all pending obligations.
    pub fn pending(&self) -> impl Iterator<Item = &SymbolicObligation> {
        self.obligations.values().filter(|o| o.is_pending())
    }

    /// Returns obligations for a specific symbol.
    pub fn by_symbol(&self, symbol_id: SymbolId) -> Vec<&SymbolicObligation> {
        self.by_symbol
            .get(&symbol_id)
            .map(|ids| {
                ids.iter()
                    .filter_map(|id| self.obligations.get(id))
                    .collect()
            })
            .unwrap_or_default()
    }

    /// Returns the count of pending obligations.
    #[must_use]
    pub fn pending_count(&self) -> usize {
        self.obligations.values().filter(|o| o.is_pending()).count()
    }

    /// Checks for leaked obligations and marks them.
    /// Called during region close.
    pub fn check_leaks(&mut self) -> Vec<ObligationId> {
        let mut leaked = Vec::new();
        for (id, ob) in self.obligations.iter_mut() {
            if ob.is_pending() {
                ob.mark_leaked();
                leaked.push(*id);
            }
        }
        leaked
    }

    /// Aborts all pending obligations due to epoch expiry.
    pub fn abort_expired_epoch(&mut self, current_epoch: EpochId) -> Vec<ObligationId> {
        let mut aborted = Vec::new();
        for (id, ob) in self.obligations.iter_mut() {
            if ob.is_pending() && !ob.is_epoch_valid(current_epoch) {
                ob.abort();
                aborted.push(*id);
            }
        }
        aborted
    }

    /// Aborts all pending obligations due to deadline expiry.
    pub fn abort_expired_deadlines(&mut self, now: Time) -> Vec<ObligationId> {
        let mut aborted = Vec::new();
        for (id, ob) in self.obligations.iter_mut() {
            if ob.is_pending() && ob.is_expired(now) {
                ob.abort();
                aborted.push(*id);
            }
        }
        aborted
    }
}

/// Guard that commits an obligation on successful scope exit.
pub struct ObligationGuard<'a> {
    tracker: &'a mut SymbolicObligationTracker,
    id: ObligationId,
    resolved: bool,
}

impl<'a> ObligationGuard<'a> {
    /// Creates a new guard for the given obligation.
    pub fn new(tracker: &'a mut SymbolicObligationTracker, id: ObligationId) -> Self {
        Self {
            tracker,
            id,
            resolved: false,
        }
    }

    /// Commits the obligation and marks the guard as resolved.
    pub fn commit(mut self) {
        self.tracker.resolve(self.id, true);
        self.resolved = true;
    }

    /// Aborts the obligation and marks the guard as resolved.
    pub fn abort(mut self) {
        self.tracker.resolve(self.id, false);
        self.resolved = true;
    }
}

impl<'a> Drop for ObligationGuard<'a> {
    fn drop(&mut self) {
        // If not explicitly resolved, abort on drop
        if !self.resolved {
            self.tracker.resolve(self.id, false);
        }
    }
}
