## Integration Patterns

### Pattern 1: Symbol Transmission with Obligation Tracking

```rust
async fn send_symbol(
    cx: &Cx,
    tracker: &mut SymbolicObligationTracker,
    symbol: Symbol,
    destination: RegionId,
) -> Result<(), Error> {
    // Create obligation for transmit
    let ob = SymbolicObligation::transmit(
        generate_obligation_id(),
        cx.task_id(),
        cx.region_id(),
        symbol.id(),
        destination,
        Some(cx.budget().deadline()),
        None, // No epoch constraint for local
    );

    let ob_id = tracker.register(ob);

    // Perform actual send
    match transport.send(symbol).await {
        Ok(()) => {
            tracker.resolve(ob_id, true); // Commit on success
            Ok(())
        }
        Err(e) => {
            tracker.resolve(ob_id, false); // Abort on failure
            Err(e)
        }
    }
}
```

### Pattern 2: Decoding with Progress Tracking

```rust
async fn decode_object(
    cx: &Cx,
    tracker: &mut SymbolicObligationTracker,
    decoder: &mut Decoder,
    params: ObjectParams,
    epoch_window: EpochWindow,
) -> Result<Vec<u8>, Error> {
    // Create decoding obligation
    let ob = SymbolicObligation::decoding(
        generate_obligation_id(),
        cx.task_id(),
        cx.region_id(),
        params.object_id,
        params.symbols_per_block as u32,
        epoch_window,
    );

    let ob_id = tracker.register(ob);

    loop {
        cx.checkpoint()?;

        match receive_symbol().await {
            Ok(symbol) => {
                decoder.add_symbol(symbol);

                // Update progress
                tracker.obligations.get_mut(&ob_id)
                    .map(|o| o.update_decoding_progress(decoder.symbol_count()));

                if decoder.can_decode() {
                    let data = decoder.decode()?;
                    tracker.resolve(ob_id, true);
                    return Ok(data);
                }
            }
            Err(e) => {
                tracker.resolve(ob_id, false);
                return Err(e);
            }
        }
    }
}
```

### Pattern 3: Lease-Based Resource Access

```rust
async fn with_remote_resource<T>(
    cx: &Cx,
    tracker: &mut SymbolicObligationTracker,
    object_id: ObjectId,
    lease_duration: Duration,
    f: impl FnOnce() -> Result<T, Error>,
) -> Result<T, Error> {
    let lease_expires = cx.budget().deadline().min(
        Time::from_nanos(std::time::Instant::now().elapsed().as_nanos() as u64)
            .saturating_add_nanos(lease_duration.as_nanos() as u64)
    );

    // Create lease obligation
    let ob = SymbolicObligation::lease(
        generate_obligation_id(),
        cx.task_id(),
        cx.region_id(),
        object_id,
        lease_expires,
    );

    let ob_id = tracker.register(ob);
    let guard = ObligationGuard::new(tracker, ob_id);

    let result = f();

    if result.is_ok() {
        guard.commit();
    } else {
        guard.abort();
    }

    result
}
