    // Test 10: Decoding progress updates
    #[test]
    fn test_decoding_progress_update() {
        let (oid, tid, rid) = test_ids();
        let object_id = ObjectId::new_for_test(1);
        let window = EpochWindow {
            start: EpochId(1),
            end: EpochId(100),
        };

        let mut ob = SymbolicObligation::decoding(
            oid, tid, rid, object_id, 10, window
        );

        // Initial state
        if let SymbolObligationKind::DecodingInProgress { symbols_received, .. } = ob.symbol_kind() {
            assert_eq!(*symbols_received, 0);
        }

        // Update progress
        ob.update_decoding_progress(5);

        if let SymbolObligationKind::DecodingInProgress { symbols_received, .. } = ob.symbol_kind() {
            assert_eq!(*symbols_received, 5);
        }
    }

    // Test 11: Double resolution panics
    #[test]
    #[should_panic(expected = "obligation already resolved")]
    fn test_double_commit_panics() {
        let (oid, tid, rid) = test_ids();
        let symbol_id = SymbolId::new_for_test(1, 0, 0);
        let dest = RegionId::from_arena(ArenaIndex::new(1, 0));

        let mut ob = SymbolicObligation::transmit(
            oid, tid, rid, symbol_id, dest, None, None
        );

        ob.commit();
        ob.commit(); // Should panic
    }

    // Test 12: No epoch constraint means always valid
    #[test]
    fn test_no_epoch_constraint_always_valid() {
        let (oid, tid, rid) = test_ids();
        let symbol_id = SymbolId::new_for_test(1, 0, 0);

        let ob = SymbolicObligation::ack(
            oid, tid, rid, symbol_id, rid
        );

        // With no epoch constraint, any epoch is valid
        assert!(ob.is_epoch_valid(EpochId(0)));
        assert!(ob.is_epoch_valid(EpochId(u64::MAX)));
    }
}
```

## Logging Strategy

```rust
use crate::observability::{LogEntry, LogLevel};

/// Logging for symbolic obligation operations.
impl SymbolicObligationTracker {
    fn log_register(&self, ob: &SymbolicObligation) -> LogEntry {
        LogEntry::debug("Symbolic obligation registered")
            .with_field("obligation_id", &format!("{:?}", ob.id()))
            .with_field("kind", &format!("{:?}", ob.symbol_kind()))
            .with_field("region_id", &format!("{}", self.region_id))
    }

    fn log_resolve(&self, ob: &SymbolicObligation, committed: bool) -> LogEntry {
        let level = if committed { LogLevel::Debug } else { LogLevel::Info };
        LogEntry::new(level, "Symbolic obligation resolved")
            .with_field("obligation_id", &format!("{:?}", ob.id()))
            .with_field("committed", &committed.to_string())
            .with_field("state", &format!("{:?}", ob.state()))
    }

    fn log_leak(&self, ob_id: ObligationId) -> LogEntry {
        LogEntry::error("Symbolic obligation leaked")
            .with_field("obligation_id", &format!("{:?}", ob_id))
            .with_field("region_id", &format!("{}", self.region_id))
    }

    fn log_epoch_abort(&self, ob_id: ObligationId, current_epoch: EpochId) -> LogEntry {
        LogEntry::warn("Symbolic obligation aborted due to epoch expiry")
            .with_field("obligation_id", &format!("{:?}", ob_id))
            .with_field("current_epoch", &format!("{}", current_epoch.0))
    }

    fn log_deadline_abort(&self, ob_id: ObligationId, now: Time) -> LogEntry {
        LogEntry::warn("Symbolic obligation aborted due to deadline expiry")
            .with_field("obligation_id", &format!("{:?}", ob_id))
            .with_field("current_time", &format!("{}", now))
    }
}
